VALUES
  ('elementary-0a2fc18c-moex-00733', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於貪污治罪條例相關法條之敘述，何者錯誤？', '["對於公務員違背職務之行為，要求、期約或收受賄賂或其他不正利益者，構成犯罪", "對於公務員職務上之行為，要求、期約或收受賄賂或其他不正利益者，不構成犯罪", "對於主管或監督之事務，明知違背法令等規定，直接或間接圖自己或其他私人不法利益，因而獲得利 益者，構成犯罪", "對於非主管或監督之事務，明知違背法令等規定，利用職權機會或身分圖自己或其他私人不法利益， 因而獲得利益者，構成犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00734', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲犯侵占罪，尚未被發覺，妻子乙為庇護甲而出面向警方表示係其犯罪，乙是否符合刑法自首要件？', '["不符合，因警方並非偵查機關，向警方自首，於法未合", "符合，因犯罪既尚未被發覺，乙出面向警方坦承犯行，當屬自首", "不符合，因乙非侵占罪行為人，乙自無自首問題", "符合，因可以轉換成乙所犯頂替罪之自首"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00735', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '關於刑法上之故意犯與過失犯，下列敘述何者正確？', '["行為非出於故意者，即係出於過失", "間接故意犯與有認識過失犯之罪質相當", "刑法以處罰故意犯為原則，但過失犯情節嚴重者，仍應與故意犯同視", "過失犯之處罰以法律有明文者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00736', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列有關刑法第138條侵害公務上掌管文書物品罪之敘述，何者錯誤？', '["甲收到法院寄發之傳票後，將之撕毀，甲成立本罪", "甲撕毀警員乙依法制作之談話筆錄，甲成立本罪", "甲與警員乙發生拉扯，致乙所穿制服毀損，甲不成立本罪", "警員乙將經扣押之物交由該物之所有權人甲暫時保管，甲故意將之毀損，甲成立本罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00737', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '刑法第17條因犯罪致發生一定之結果，而有加重其刑之規定者，如行為人不能預見其發生時，不適用之。 依實務見解，下列敘述何者錯誤？', '["必須行為人主觀上有預見結果發生", "本條在學理上稱為加重結果犯", "必須刑法條文有特別規定才有適用", "基礎犯罪與發生結果間須具備因果關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00738', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '行政程序法第3條第3項明列特定事項不適用該法之程序規定，下列何種行為即屬該法所定排除之事項？', '["內政部移民署依法禁止本國人出境", "高雄市警察局員警依據集會遊行法規定命令群眾立即解散", "國防部將部隊連級主官調任為內部單位參謀", "私立大學依據該校規定對特定學生為記過處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00739', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設A國只生產香蕉與電腦兩種產品，如果強烈颱風吹倒A國一半香蕉樹，則A國的生產可能曲線將會 如何變化？', '["外移", "內縮", "不變", "無法判斷外移或內縮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00740', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', 'A國對B國進口的機車實施進口限額管制導致機車進口量下降，相對於進口限額政策實施前，實施後A 國機車市場的變化為何？', '["消費者剩餘上升", "生產者剩餘上升", "社會福利上升", "社會福利不變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00741', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設A國只生產小麥與腳踏車兩種產品且每月有效率的生產小麥5萬公噸、腳踏車8萬部，A國換過行 政團隊後，每個月可以提供小麥6萬公噸、腳踏車9萬部供A國民眾消費，請問新行政團隊可能做了什 麼事？', '["調降所得稅", "補貼生產者", "引導本國貨幣升值", "開放國際貿易"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00742', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '關於經濟學相關的敘述，下列何者錯誤？', '["經濟學之父為亞當斯密（AdamSmith）", "規範經濟學是講述真假的事實，而不涉及好壞的價值判斷", "經濟學是教導在資源有限、慾望無窮下，如何進行選擇的科學", "資訊不對稱、公共財、外部性等課題都是屬於市場失靈的範疇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
